439	// OperatorPromptCancel implements the operatorPromptCancel mutation:
440	// validates CSRF, verifies the bead is a proposed operator-prompt,
441	// transitions proposed → cancelled, and appends an audit event recording
442	// the canceller. Cancellation is open to any trusted identity (the
443	// allowlist gates auto-approval, not rejection) so an operator who
444	// regrets a submission can withdraw it without first being added to the
445	// approval allowlist.
446	func (r *mutationResolver) OperatorPromptCancel(ctx context.Context, id string) (*OperatorPromptCancelResult, error) {
447		httpReq, ident, err := r.requireOperatorPromptCSRF(ctx)
448		if err != nil {
449			return nil, err
450		}
451	
452		store := r.beadStore()
453		existing, err := store.Get(id)
454		if err != nil {
455			return nil, err
456		}
457		if existing.IssueType != bead.IssueTypeOperatorPrompt {
458			return nil, fmt.Errorf("operator-prompts: bead %s is not an operator-prompt (issue_type=%q)", id, existing.IssueType)
459		}
460		if existing.Status != bead.StatusProposed {
461			return nil, fmt.Errorf("operator-prompts: bead %s is not in proposed status (got %q); cannot cancel", id, existing.Status)
462		}
463		if err := store.Update(id, func(b *bead.Bead) {
464			b.Status = bead.StatusCancelled
465		}); err != nil {
466			return nil, err
467		}
468		if err := store.AppendEvent(id, bead.BeadEvent{
469			Kind:    OperatorPromptCancelEventKind,
470			Summary: "operator prompt cancelled",
471			Body:    fmt.Sprintf("identity=%s actor=%s remote_addr=%s", ident.kind, ident.actor, httpReq.RemoteAddr),
472			Actor:   ident.actor,
473			Source:  "graphql:operatorPromptCancel",
474		}); err != nil {
475			return nil, fmt.Errorf("operator-prompts: append cancel audit event: %w", err)
476		}
477		persisted, err := store.Get(id)
478		if err != nil {
479			return nil, err
480		}
481		return &OperatorPromptCancelResult{Bead: beadModelFromBead(persisted)}, nil
482	}
483	
484	// requireOperatorPromptCSRF is the shared preamble for the approve and
485	// cancel mutations. It pulls the originating *http.Request from context
486	// (the server's GraphQL handler installs it via WithHTTPRequest), enforces
487	// the CSRF token check against the configured store, and returns the
488	// classified identity.
489	func (r *mutationResolver) requireOperatorPromptCSRF(ctx context.Context) (*http.Request, operatorPromptIdentityInfo, error) {
490		if r.WorkingDir == "" {
491			return nil, operatorPromptIdentityInfo{}, fmt.Errorf("working directory not configured")
492		}
493		httpReq := httpRequestFromContext(ctx)
494		if httpReq == nil {
495			return nil, operatorPromptIdentityInfo{}, errCSRF
496		}
497		presented := httpReq.Header.Get(CSRFHeaderName)
498		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
499			return nil, operatorPromptIdentityInfo{}, errCSRF
500		}
501		return httpReq, operatorPromptIdentity(httpReq), nil
502	}
503	
504	// canSubmit reports whether ident is authorized to submit operator prompts
505	// for this project. Localhost identities are always allowed (they have
506	// already cleared the requireTrusted loopback gate, which is the project's
507	// strongest trust signal). ts-net identities must appear in the per-project
508	// OperatorPromptAutoApproveAllowlist (the same list that gates approval —
509	// per Story 15 the project's "allow_identities" config is one allowlist
510	// serving both submit-by-tsnet and approve-by-localhost). An empty list
511	// rejects every ts-net peer, yielding the documented "ts-net peers see
512	// read-only UI" default.
513	func (r *Resolver) canSubmit(ident operatorPromptIdentityInfo) bool {
514		if ident.kind == "localhost" {
515			return true
516		}
517		if ident.kind != "tsnet" {
518			return false
519		}
520		for _, entry := range r.OperatorPromptAutoApproveAllowlist {
521			if entry == ident.actor {
522				return true
523			}
524		}
525		return false
526	}
527	
528	// canAutoApprove reports whether ident is authorized to approve operator
529	// prompts under the resolver's allowlist. ts-net identities are denied
530	// unconditionally (locked Story 15 decision). For localhost identities,
531	// the literal sentinel "localhost" matches any actor; otherwise the
532	// allowlist entry must equal the identity's actor string.
533	func (r *Resolver) canAutoApprove(ident operatorPromptIdentityInfo) bool {
534		if ident.kind != "localhost" {
535			return false
536		}
537		if len(r.OperatorPromptAutoApproveAllowlist) == 0 {
538			return false
539		}
540		for _, entry := range r.OperatorPromptAutoApproveAllowlist {
541			if entry == OperatorPromptAllowlistLocalhostSentinel {
542				return true
543			}
544			if entry == ident.actor {
545				return true
546			}
547		}
548		return false
549	}
550	
551	type operatorPromptIdentityInfo struct {
552		kind  string // "tsnet" or "localhost"
553		actor string
554	}
555	
556	// operatorPromptIdentity classifies the originating identity for audit
557	// logging. ts-net peers are identified by the X-Tailscale-User header
558	// injected by tsnetMiddleware; loopback callers fall back to a
559	// "localhost:<remote-addr>" actor string. A bare "anonymous" actor is used
560	// only when neither signal is present (which should not occur because
561	// requireTrusted gates the GraphQL endpoint).
562	func operatorPromptIdentity(r *http.Request) operatorPromptIdentityInfo {
563		if user := r.Header.Get("X-Tailscale-User"); user != "" {
564			return operatorPromptIdentityInfo{kind: "tsnet", actor: user}
565		}
566		if r.RemoteAddr != "" {
567			return operatorPromptIdentityInfo{kind: "localhost", actor: "localhost:" + r.RemoteAddr}
568		}
569		return operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
570	}
571	
572	// validateSameOrigin enforces strict Origin/Host equality on prompt-driven
573	// mutations. When the request carries an Origin header (every browser POST
574	// does), the host portion must match the request Host — this rejects
575	// browser cross-origin POSTs even from a trusted-loopback peer (defense in
576	// depth alongside the per-session CSRF token). Non-browser clients (curl,
577	// the SvelteKit fetch wrapper running same-origin) either omit Origin or
578	// emit an Origin matching Host, so they pass through unchanged.
579	func validateSameOrigin(r *http.Request) error {
580		origin := r.Header.Get("Origin")
581		if origin == "" {
582			// No Origin -> not a browser cross-origin POST. CSRF token is the
583			// remaining gate.
584			return nil
585		}
586		parsed, err := url.Parse(origin)
587		if err != nil || parsed.Host == "" {
588			return errCrossOrigin
589		}
590		if !sameHost(parsed.Host, r.Host) {
591			return errCrossOrigin
592		}
593		return nil
594	}
595	
596	// sameHost compares two host[:port] strings tolerating an absent port (a
597	// browser may omit :443 from Origin while the request Host carries it, or
598	// vice versa). The comparison is case-insensitive on the host component.
599	func sameHost(a, b string) bool {
600		ah, _ := splitHostPort(a)
601		bh, _ := splitHostPort(b)
602		if !strings.EqualFold(ah, bh) {
603			return false
604		}
605		// Reject when both sides carry a port and they disagree; tolerate the
606		// "one side omits the port" case (default-port elision by the browser).
607		_, ap := splitHostPort(a)
608		_, bp := splitHostPort(b)
609		if ap != "" && bp != "" && ap != bp {
610			return false
611		}
612		return true
613	}
614	
615	func splitHostPort(hp string) (string, string) {
616		if i := strings.LastIndex(hp, ":"); i > 0 && !strings.Contains(hp[i:], "]") {
617			return hp[:i], hp[i+1:]
618		}
619		return hp, ""
620	}
