622	// newRequestID returns a 16-byte hex random string used as the request ID
623	// recorded on the audit event when the caller does not supply X-Request-Id.
624	func newRequestID() string {
625		var buf [16]byte
626		if _, err := rand.Read(buf[:]); err != nil {
627			return "no-request-id"
628		}
629		return hex.EncodeToString(buf[:])
630	}
